using namespace cute;
template<typename Kernel_traits, int NTILES, bool Is_even_MN, bool Is_even_K>
inline **device** void compute_mla_attn_1rowblock(const Mla_fwd_params &params,
                                                  const int bidb, const int bidh, const int m_block) {
    using Element = typename Kernel_traits::Element;           // cutlass::bfloat16_t
    using ElementAccum = typename Kernel_traits::ElementAccum; // float
    using index_t = typename Kernel_traits::index_t;
    extern **shared** char smem_[];
    const int tidx = threadIdx.x;
    constexpr int kBlockM  = Kernel_traits::kBlockM;
    constexpr int kBlockN  = Kernel_traits::kBlockN;
    constexpr int kHeadDim = Kernel_traits::kHeadDim; // 必须是 128
    constexpr int kNWarps  = Kernel_traits::kNWarps;
    // Basic bounds
    const int seqlen_q = params.seqlen_q;
    if (m_block * kBlockM >= seqlen_q) return;
    // per-batch valid kv length
    const int kv_len = params.kv_valid_len[bidb];
    // early exit if kv_len==0
    if (kv_len <= 0) return;
    const int past = kv_len - seqlen_q;
    // Determine n_block range (use kv_len, not seqlen_k)
    int n_block_min = 0;
    int n_block_max = (kv_len + kBlockN - 1) / kBlockN;
    if (params.causal) {
        // max visible key for this m_block (append causal)
        const int q_end = min((m_block + 1) * kBlockM, seqlen_q) - 1;  // row idx within chunk
        const int max_k = past + q_end;
        const int causal_max = (max_k + 1 + kBlockN - 1) / kBlockN;
        n_block_max = min(n_block_max, causal_max);
    }
    if (n_block_max <= n_block_min) {
        // TODO: write zeros to O slice [dv_start, dv_start+dv_len) for this m_block
        return;
    }
    // --- Build base pointers (element strides) ---
    // q_ptr layout: [b, h, seqlen_q, dc]
    Element* q_base = reinterpret_cast<Element*>(params.q_ptr)
        + bidb * params.q_batch_stride
        + bidh * params.q_head_stride;
    // k_ptr layout: [b, 1, seqlen_k, dc]  (head broadcast)
    Element* k_base = reinterpret_cast<Element*>(params.k_ptr)
        + bidb * params.k_batch_stride;
    // o_ptr layout: [b, h, seqlen_q, dc]
    Element* o_base = reinterpret_cast<Element*>(params.o_ptr)
        + bidb * params.o_batch_stride
        + bidh * params.o_head_stride;
    // --- Construct global tensors with last-dim = dc (not 128) ---
    // mQ: (seqlen_q, dc)
    Tensor mQ = make_tensor(make_gmem_ptr(q_base),
                            make_shape(seqlen_q, params.dc),
                            make_stride(params.q_row_stride, _1{}));
    // mK/mV: (kv_len, dc)
    Tensor mK = make_tensor(make_gmem_ptr(k_base),
                            make_shape(kv_len, params.dc),
                            make_stride(params.k_row_stride, _1{}));
    Tensor mV = mK;
    // Shared memory tensors (exactly like flash-attn)
    Tensor sQ = make_tensor(make_smem_ptr(reinterpret_cast<Element*>(smem_)),
                            typename Kernel_traits::SmemLayoutQ{});
    Tensor sK = make_tensor(sQ.data() + (Kernel_traits::Share_Q_K_smem ? 0 : size(sQ)),
                            typename Kernel_traits::SmemLayoutKV{});
    Tensor sV = make_tensor(sK.data() + size(sK), typename Kernel_traits::SmemLayoutKV{});
    Tensor sVt = make_tensor(sV.data(), typename Kernel_traits::SmemLayoutVtransposed{});
    Tensor sVtNoSwizzle = make_tensor(sV.data().get(), typename Kernel_traits::SmemLayoutVtransposedNoSwizzle{});
    // Copy objects
    typename Kernel_traits::GmemTiledCopyQKV gmem_tiled_copy_QKV;
    auto gmem_thr_copy_QKV = gmem_tiled_copy_QKV.get_thread_slice(tidx);
    typename Kernel_traits::TiledMma tiled_mma;
    auto thr_mma = tiled_mma.get_thread_slice(tidx);
    Tensor tSrQ = thr_mma.partition_fragment_A(sQ);
    Tensor tSrK = thr_mma.partition_fragment_B(sK);
    Tensor tOrVt = thr_mma.partition_fragment_B(sVtNoSwizzle);
    // smem copy atoms (reuse from flash)
    auto smem_tiled_copy_Q = make_tiled_copy_A(typename Kernel_traits::SmemCopyAtom{}, tiled_mma);
    auto smem_thr_copy_Q = smem_tiled_copy_Q.get_thread_slice(tidx);
    Tensor tSsQ = smem_thr_copy_Q.partition_S(sQ);
    auto smem_tiled_copy_K = make_tiled_copy_B(typename Kernel_traits::SmemCopyAtom{}, tiled_mma);
    auto smem_thr_copy_K = smem_tiled_copy_K.get_thread_slice(tidx);
    Tensor tSsK = smem_thr_copy_K.partition_S(sK);
    auto smem_tiled_copy_V = make_tiled_copy_B(typename Kernel_traits::SmemCopyAtomTransposed{}, tiled_mma);
    auto smem_thr_copy_V = smem_tiled_copy_V.get_thread_slice(tidx);
    Tensor tOsVt = smem_thr_copy_V.partition_S(sVt);
    // multi-tile acc_o
    Tensor acc_o[NTILES];
    #pragma unroll
    for (int i = 0; i < NTILES; ++i) {
        acc_o[i] = partition_fragment_C(tiled_mma, Shape<Int<kBlockM>, Int<kHeadDim>>{});
        clear(acc_o[i]);
    }
    // Softmax object (same template size)
    Softmax<2 * size<1>(acc_o[0])> softmax;
    // iterate blocks (simple forward order first)
    for (int n_block = n_block_min; n_block < n_block_max; ++n_block) {
        // QK accumulator
        Tensor acc_s = partition_fragment_C(tiled_mma, Shape<Int<kBlockM>, Int<kBlockN>>{});
        clear(acc_s);
        // ---- dc loop: accumulate Q_nope @ K_nope^T over dv slices ----
        for (int dv = 0; dv < params.dc; dv += kHeadDim) {
            // Q slice: (kBlockM, 128) at (m_block, dv)
            Tensor gQ = local_tile(mQ, Shape<Int<kBlockM>, Int<kHeadDim>>{}, make_coord(m_block, dv));
            // K slice: (kBlockN, 128) at (n_block, dv)
            Tensor gK = local_tile(mK, Shape<Int<kBlockN>, Int<kHeadDim>>{}, make_coord(n_block, dv));
            // Partition for copy
            Tensor tQgQ = gmem_thr_copy_QKV.partition_S(gQ);
            Tensor tQsQ = gmem_thr_copy_QKV.partition_D(sQ);
            Tensor tKgK = gmem_thr_copy_QKV.partition_S(gK);
            Tensor tKsK = gmem_thr_copy_QKV.partition_D(sK);
            // Copy to smem (Phase1: assume even-K for 128 tiles)
            FLASH_NAMESPACE::copy</*Is_even_MN=*/false, /*Is_even_K=*/true>(gmem_tiled_copy_QKV, tQgQ, tQsQ);
            FLASH_NAMESPACE::copy</*Is_even_MN=*/false, /*Is_even_K=*/true>(gmem_tiled_copy_QKV, tKgK, tKsK);
            cute::cp_async_fence();
            FLASH_NAMESPACE::cp_async_wait<0>();
            __syncthreads();
            // GEMM accumulate acc_s += Q_slice @ K_slice^T
            FLASH_NAMESPACE::gemm</*A_in_regs=*/Kernel_traits::Is_Q_in_regs>(
                acc_s, tSrQ, tSrK, tSsQ, tSsK, tiled_mma, smem_tiled_copy_Q, smem_tiled_copy_K,
                smem_thr_copy_Q, smem_thr_copy_K
            );
            __syncthreads();
        }
        // scale
        // (flash-attn uses scale_softmax_log2 inside softmax, so here you typically keep acc_s unscaled or scaled appropriately)
        // For Phase1 simplest: rely on softmax_rescale_o with params.scale_softmax_log2 and set params.scale_softmax_log2 accordingly.
        // mask acc_s (padding + append causal)
        apply_mask_mla(acc_s,
                       /*n_offset=*/n_block * kBlockN,
                       /*m_offset=*/m_block * kBlockM,
                       kBlockM, kBlockN,
                       seqlen_q, kv_len, past,
                       tidx, kNWarps);
        // rescale all tiles
        #pragma unroll
        for (int i = 0; i < NTILES; ++i) {
            if (n_block == n_block_min) {
                softmax.template softmax_rescale_o</*Is_first=*/true,  /*Check_inf=*/true>(acc_s, acc_o[i], params.scale_softmax_log2);
            } else {
                softmax.template softmax_rescale_o</*Is_first=*/false, /*Check_inf=*/true>(acc_s, acc_o[i], params.scale_softmax_log2);
            }
        }
        // P fragment
        Tensor rP = FLASH_NAMESPACE::convert_type<Element>(acc_s);
        Tensor tOrP = make_tensor(rP.data(),
                                 FLASH_NAMESPACE::convert_layout_acc_Aregs<typename Kernel_traits::TiledMma>(rP.layout()));
        // PV tiles
        #pragma unroll
        for (int i = 0; i < NTILES; ++i) {
            const int dv_out = params.dv_start + i * kHeadDim;
            // V slice: (kBlockN, 128) at (n_block, dv_out)
            Tensor gV = local_tile(mV, Shape<Int<kBlockN>, Int<kHeadDim>>{}, make_coord(n_block, dv_out));
            Tensor tVgV = gmem_thr_copy_QKV.partition_S(gV);
            Tensor tVsV = gmem_thr_copy_QKV.partition_D(sV);
            FLASH_NAMESPACE::copy</*Is_even_MN=*/false, /*Is_even_K=*/true>(gmem_tiled_copy_QKV, tVgV, tVsV);
            cute::cp_async_fence();
            FLASH_NAMESPACE::cp_async_wait<0>();
            __syncthreads();
            FLASH_NAMESPACE::gemm_rs(acc_o[i], tOrP, tOrVt, tOsVt, tiled_mma, smem_tiled_copy_V, smem_thr_copy_V);
            __syncthreads();
        }
    }
    // ---- finalize: apply inv_l to each acc_o tile (requires softmax.h change) ----
    // auto inv_l = softmax.get_inv_l();     // TODO: implement in softmax.h
    // #pragma unroll
    // for (int i=0;i<NTILES;++i) { softmax.apply_inv_l(acc_o[i], inv_l); }
    // ---- store each tile to output ----
    // We'll write (kBlockM, 128) tiles to O at dv = dv_start + i*128
    // Construct output tensor mO: (seqlen_q, dc)
    /*
    Tensor mO = make_tensor(make_gmem_ptr(o_base),
                            make_shape(seqlen_q, params.dc),
                            make_stride(params.o_row_stride, _1{}));
    #pragma unroll
    for (int i = 0; i < NTILES; ++i) {
        const int dv_out = params.dv_start + i * kHeadDim;
        Tensor gO = local_tile(mO, Shape<Int<kBlockM>, Int<kHeadDim>>{}, make_coord(m_block, dv_out));
        Tensor rO = FLASH_NAMESPACE::convert_type<Element>(acc_o[i]);
        // Use existing gmem tiled copy for O (same as kernel_traits)
        typename Kernel_traits::GmemTiledCopyO gmem_tiled_copy_O;
        auto gmem_thr_copy_O = gmem_tiled_copy_O.get_thread_slice(tidx);
        Tensor tOgO = gmem_thr_copy_O.partition_D(gO);
        Tensor tOrO = gmem_thr_copy_O.partition_S(rO); // might need retile depending on layout
        // TODO: You may need to follow flash epilogue path (copy rO -> sO -> gO) for correct layout.
        // For first version, you can do a simpler direct copy if layout matches.
        cute::copy(tOrO, tOgO);
    }
    */
    // === Epilogue: store each 128-wide tile using the same path as flash-attn (rO -> sO -> gO) ===
    // Reuse sQ's memory as sO staging (same as flash-attn)
    Tensor sO = make_tensor(sQ.data(), typename Kernel_traits::SmemLayoutO{});  // (SMEM_M, SMEM_N)
    // Smem store for O
    auto smem_tiled_copy_O = make_tiled_copy_C(typename Kernel_traits::SmemCopyAtomO{}, tiled_mma);
    auto smem_thr_copy_O = smem_tiled_copy_O.get_thread_slice(tidx);
    Tensor taccOsO = smem_thr_copy_O.partition_D(sO);  // ((Atom,AtomNum), PIPE_M, PIPE_N)
    // Global output tensor (seqlen_q, dc)
    Tensor mO = make_tensor(make_gmem_ptr(o_base),
                            make_shape(seqlen_q, params.dc),
                            make_stride(params.o_row_stride, _1{}));
    typename Kernel_traits::GmemTiledCopyO gmem_tiled_copy_O;
    auto gmem_thr_copy_gO = gmem_tiled_copy_O.get_thread_slice(tidx);
    Tensor tOsO = gmem_thr_copy_gO.partition_S(sO);  // ((Atom,AtomNum), ATOM_M, ATOM_N)
    #pragma unroll
    for (int i = 0; i < NTILES; ++i) {
        const int dv_out = params.dv_start + i * kHeadDim;  // kHeadDim==128
        // gO tile: (kBlockM, 128) at (m_block, dv_out)
        Tensor gO = local_tile(mO, Shape<Int<kBlockM>, Int<kHeadDim>>{}, make_coord(m_block, dv_out));
        Tensor rO = FLASH_NAMESPACE::convert_type<Element>(acc_o[i]);
        // Partition rO and gO according to the gmem copy
        Tensor taccOrO = smem_thr_copy_O.retile_S(rO);         // ((Atom,AtomNum), MMA_M, MMA_N)
        // NOTE: taccOsO already points to sO
        // If Share_Q_K_smem, need to sync before reusing sQ as sO (same as original flash-attn)
        if (Kernel_traits::Share_Q_K_smem) { __syncthreads(); }
        // 1) write rO to shared sO
        cute::copy(smem_tiled_copy_O, taccOrO, taccOsO);
        // 2) write shared sO to global gO
        Tensor tOgO = gmem_thr_copy_gO.partition_D(gO);        // ((Atom,AtomNum), ATOM_M, ATOM_N)
        // We need predicates for M (for last block) and N (should always be valid since kHeadDim=128 fixed)
        // Construct identity layout for gO to compute row index
        Tensor cO = make_identity_tensor(make_shape(size<0>(gO), size<1>(gO)));  // (BLK_M, BLK_N)
        Tensor tOcO = gmem_thr_copy_gO.partition_D(cO);
        Tensor tOpO = make_tensor<bool>(make_shape(size<2>(tOgO)));
        // N pred: always true since tile width is exactly 128 and dv_out+128 <= dc is guaranteed by NTILES and dv_len.
        // M pred: ensure we don't write beyond seqlen_q in last block.
        #pragma unroll
        for (int k = 0; k < size(tOpO); ++k) {
            // row index within this tile
            int row = get<0>(tOcO(0, 0, k));
            tOpO(k) = (row < seqlen_q - m_block * kBlockM);
        }
        // Make sure sO is ready
        __syncthreads();
        // Clear_OOB_K must be false; Clear_OOB_MN true to prevent OOB rows writes
        FLASH_NAMESPACE::copy</*Is_even_MN=*/false, /*Is_even_K=*/true, /*Clear_OOB_MN=*/true, /*Clear_OOB_K=*/false>(
            gmem_tiled_copy_O, tOsO, tOgO, tOcO, tOpO, seqlen_q - m_block * kBlockM
        );
        __syncthreads();
    }
