struct Mla_fwd_params {
  using index_t = int64_t;
  // q_nope: [b, h, seqlen_q, dc]
  void* **restrict** q_ptr;
  index_t q_batch_stride, q_row_stride, q_head_stride;
  // k_nope/v: [b, 1, seqlen_k, dc]
  void* **restrict** k_ptr;
  index_t k_batch_stride, k_row_stride;  // head=1 broadcast
  // out: [b, h, seqlen_q, dc]
  void* **restrict** o_ptr;
  index_t o_batch_stride, o_row_stride, o_head_stride;
  int b, h;
  int seqlen_q, seqlen_k;
  int dc;  // 896 or 512
  float scale_softmax;
  float scale_softmax_log2;
  const int* **restrict** kv_valid_len; // [b] int32
  int dv_start; // 0 or 512
  int dv_len;   // 512 or 384 (multiple of 128)
  bool causal;
};
